def test_update_item_success(client):
    """UNIVERSAL test for maximum coverage."""
    """Test successful update of an item."""
    # Create an item first
    create_response = client.post("/items/", json={
        "name": "Test Item",
        "description": "A test item",
        "price": 10.0,
        "quantity": 5
    })
    assert create_response.status_code == 201
    created_item = create_response.json()
    item_id = created_item["id"]

    # Update the item
    update_response = client.put(f"/items/{item_id}", json={
        "name": "Updated Item",
        "description": "Updated description",
        "price": 15.0,
        "quantity": 10
    })
    assert update_response.status_code == 200
    updated_item = update_response.json()
    assert updated_item["name"] == "Updated Item"
    assert updated_item["description"] == "Updated description"
    assert updated_item["price"] == 15.0
    assert updated_item["quantity"] == 10
    assert updated_item["id"] == item_id
    assert updated_item["updated_at"] is not None

